'use strict';

const ENDPOINT = 'https://jsonplaceholder.typicode.com/posts'; // troca para sua API

function assertEl(sel) {
  const el = document.querySelector(sel);
  if (!el) throw new Error(`Elemento não encontrado: ${sel}`);
  return el;
}

const form = assertEl('#form');
const elNome = assertEl('#nome');
const elEmail = assertEl('#email');
const elIdade = assertEl('#idade');
const btnSubmit = assertEl('#submit');
const btnCancel = assertEl('#cancel');
const elSpinner = assertEl('#spinner');
const elMsg = assertEl('#msg');
const elOut = assertEl('#out');

// ----------------------------
// Estado
// ----------------------------
let state = {
  status: 'idle',       // 'idle' | 'loading' | 'success' | 'error'
  fieldErrors: {},
  message: '',
  result: null,
};

let currentController = null;

// ----------------------------
// Normalização/Validação
// ----------------------------
function normText(x) {
  return String(x ?? '').trim().replace(/\s+/g, ' ');
}

function toNumberOrNull(raw) {
  const s = String(raw ?? '').trim().replace(',', '.');
  if (s.length === 0) return null;
  const n = Number(s);
  return Number.isNaN(n) ? null : n;
}

function validarNome(raw) {
  const v = normText(raw);
  if (v.length < 3) return { ok: false, msg: 'nome deve ter 3+ caracteres' };
  return { ok: true, value: v };
}

function validarEmailSimples(raw) {
  const email = normText(raw).toLowerCase();
  if (!email) return { ok: false, msg: 'email obrigatório' };
  const parts = email.split('@');
  if (parts.length !== 2) return { ok: false, msg: 'email inválido' };
  const [u, d] = parts;
  if (!u || !d || !d.includes('.')) return { ok: false, msg: 'email inválido' };
  return { ok: true, value: email };
}

function validarIdade(raw) {
  const n = toNumberOrNull(raw);
  if (n === null) return { ok: false, msg: 'idade inválida' };
  if (!Number.isInteger(n)) return { ok: false, msg: 'idade deve ser inteira' };
  if (n < 0 || n > 130) return { ok: false, msg: 'idade fora do intervalo' };
  return { ok: true, value: n };
}

function validarForm() {
  const erros = {};

  const n = validarNome(elNome.value);
  if (!n.ok) erros.nome = n.msg;

  const e = validarEmailSimples(elEmail.value);
  if (!e.ok) erros.email = e.msg;

  const i = validarIdade(elIdade.value);
  if (!i.ok) erros.idade = i.msg;

  const ok = Object.keys(erros).length === 0;
  if (!ok) return { ok: false, erros };

  return { ok: true, payload: { nome: n.value, email: e.value, idade: i.value } };
}

// ----------------------------
// Render
// ----------------------------
function limparErros() {
  for (const el of document.querySelectorAll('[data-err]')) el.textContent = '';
}

function renderErros(erros) {
  limparErros();
  for (const [campo, msg] of Object.entries(erros)) {
    const el = document.querySelector(`[data-err="${campo}"]`);
    if (el) el.textContent = msg;
  }
}

function render() {
  btnSubmit.disabled = state.status === 'loading';
  elSpinner.style.display = state.status === 'loading' ? 'block' : 'none';

  renderErros(state.fieldErrors);

  elMsg.textContent = state.message;
  elOut.textContent = state.result ? JSON.stringify(state.result, null, 2) : '—';
}

function setState(patch) {
  state = { ...state, ...patch };
  render();
}

// ----------------------------
// Rede (timeout/cancelamento + parse seguro)
// ----------------------------
async function fetchWithTimeout(url, options = {}, ms = 4000) {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), ms);

  try {
    return await fetch(url, { ...options, signal: controller.signal });
  } finally {
    clearTimeout(id);
  }
}

async function safeReadJson(res) {
  const text = await res.text().catch(() => '');
  try {
    return { ok: true, value: JSON.parse(text) };
  } catch {
    return { ok: false, msg: 'JSON inválido', raw: text };
  }
}

// ----------------------------
// Actions
// ----------------------------
async function submit() {
  if (state.status === 'loading') return; // evita duplo submit

  const v = validarForm();
  if (!v.ok) {
    return setState({ status: 'idle', fieldErrors: v.erros, message: 'Corrija os campos', result: null });
  }

  // limpa erros e inicia loading
  setState({ status: 'loading', fieldErrors: {}, message: '', result: null });

  // cancela request anterior (se existir)
  if (currentController) currentController.abort();
  currentController = new AbortController();

  let res;
  try {
    res = await fetchWithTimeout(ENDPOINT, {
      method: 'POST',
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(v.payload),
      // signal aqui seria do controller; como fetchWithTimeout cria o seu, em produção você unificaria.
    }, 4000);
  } catch (e) {
    setState({ status: 'error', message: (e && e.name === 'AbortError') ? 'timeout/cancelado' : 'erro de rede', result: null });
    return;
  }

  const parsed = await safeReadJson(res);

  if (!res.ok) {
    const msg = parsed.ok ? (parsed.value?.error?.message ?? res.statusText) : (parsed.raw || res.statusText);
    setState({ status: 'error', message: `HTTP ${res.status}: ${msg}`, result: null });
    return;
  }

  if (!parsed.ok) {
    setState({ status: 'error', message: 'JSON inválido', result: null });
    return;
  }

  setState({ status: 'success', message: 'Enviado com sucesso', result: parsed.value });
}

function cancel() {
  if (currentController) currentController.abort();
  setState({ status: 'idle', fieldErrors: {}, message: 'cancelado', result: null });
}

// ----------------------------
// Wire
// ----------------------------
form.addEventListener('submit', (ev) => {
  ev.preventDefault();
  submit();
});

btnCancel.addEventListener('click', cancel);

render();
console.log('[submit] pronto');
